// targetScope = 'subscription' to create a resource group
targetScope = 'subscription'

param rgLocation string = deployment().location  // inherit from deployment location

resource rg 'Microsoft.Resources/resourceGroups@2021-04-01' = {
  name: 'myapp-prod'
  location: rgLocation
}

// Deploy resources into the group — resources specify their own location
module storage './storage.bicep' = {
  name: 'storage'
  scope: rg
  params: {
    // Resource location is independent of RG location
    storageLocation: 'westus2'  // different from RG in eastus
  }
}

// Good: explicit location parameter per resource
param primaryLocation string = 'eastus'
param backupStorageLocation string = 'westus2'  // geo-paired region

resource primaryStorage 'Microsoft.Storage/storageAccounts@2023-01-01' = {
  name: 'mystorageeastus'
  location: primaryLocation
  sku: { name: 'Standard_GRS' }
  kind: 'StorageV2'
}

resource backupStorage 'Microsoft.Storage/storageAccounts@2023-01-01' = {
  name: 'mystoragewestus2'
  location: backupStorageLocation  // different region from RG and primary
  sku: { name: 'Standard_LRS' }
  kind: 'StorageV2'
}

// Avoid: hardcoding resourceGroup().location for all resources
// This works but forces all resources to the same region as the RG
resource storage 'Microsoft.Storage/storageAccounts@2023-01-01' = {
  name: 'mystorage'
  location: resourceGroup().location  // OK for single-region deployments
  sku: { name: 'Standard_LRS' }
  kind: 'StorageV2'
}

// Bicep: create two paired resource groups for active-passive DR
targetScope = 'subscription'

param primaryLocation string = 'eastus2'
param secondaryLocation string = 'centralus'  // paired with eastus2
param appName string

resource rgPrimary 'Microsoft.Resources/resourceGroups@2022-09-01' = {
  name: '${appName}-primary-rg'
  location: primaryLocation
  tags: { role: 'primary', pairedWith: secondaryLocation }
}

resource rgSecondary 'Microsoft.Resources/resourceGroups@2022-09-01' = {
  name: '${appName}-secondary-rg'
  location: secondaryLocation
  tags: { role: 'secondary', pairedWith: primaryLocation }
}

// Deploy the same app stack to both
module primaryStack 'app-stack.bicep' = {
  name: 'primary-deployment'
  scope: rgPrimary
  params: { location: primaryLocation, role: 'primary' }
}

module secondaryStack 'app-stack.bicep' = {
  name: 'secondary-deployment'
  scope: rgSecondary
  params: { location: secondaryLocation, role: 'secondary' }
}

# Deny creating resource GROUPS in specific locations
# (separate from resource-level location policy)
az policy definition create \
  --name 'deny-rg-outside-eu' \
  --mode All \
  --rules '{
    "if": {
      "allOf": [
        {"field": "type", "equals": "Microsoft.Resources/subscriptions/resourceGroups"},
        {"not": {"field": "location", "in": ["northeurope","westeurope","uksouth"]}}
      ]
    },
    "then": {"effect": "deny"}
  }'

# Assign at subscription scope
az policy assignment create \
  --name 'deny-rg-outside-eu' \
  --scope /subscriptions/<subId> \
  --policy deny-rg-outside-eu

import subprocess, json

def get_all_resource_groups():
    result = subprocess.run(
        ['az', 'group', 'list', '--output', 'json'],
        capture_output=True, text=True
    )
    return json.loads(result.stdout)

def audit_rg_locations(allowed_locations):
    rgs = get_all_resource_groups()
    violations = [
        {'name': rg['name'], 'location': rg['location']}
        for rg in rgs
        if rg['location'] not in allowed_locations
    ]
    return violations

allowed = {'northeurope', 'westeurope', 'uksouth', 'ukwest'}
violations = audit_rg_locations(allowed)
if violations:
    print('Non-compliant resource groups:')
    for v in violations:
        print(f"  {v['name']}: {v['location']}")
else:
    print('All resource groups are in approved locations')
